const now = new Date();
const items = $input.all().map(item => {
  const dueAt = new Date(item.json.due_at);
  const triggeredAt = new Date(item.json.triggered_at);
  const totalWindow = dueAt - triggeredAt;
  const elapsed = now - triggeredAt;
  const remaining = dueAt - now;
  const pctElapsed = totalWindow > 0 ? elapsed / totalWindow : 0;

  let status = item.json.status;
  if (remaining <= 0) status = 'overdue';
  else if (pctElapsed >= 0.75) status = 'due_soon';

  return {
    json: {
      ...item.json,
      status,
      minutes_remaining: Math.max(0, Math.round(remaining / 60000)),
      minutes_overdue: remaining < 0 ? Math.round(-remaining / 60000) : 0,
      pct_elapsed: Math.round(pctElapsed * 100)
    }
  };
});
return items;

const alerts = $input.all();
const overdue = alerts.filter(a => a.json.status === 'overdue');
const dueSoon = alerts.filter(a => a.json.status === 'due_soon');

const summary = {
  total_alerts: alerts.length,
  overdue: overdue.length,
  due_soon: dueSoon.length,
  worst_overdue_minutes: Math.max(...overdue.map(a => a.json.minutes_overdue), 0),
  details: alerts.map(a => ({
    lead_id: a.json.lead_id,
    channel: a.json.channel,
    status: a.json.status,
    remaining_min: a.json.minutes_remaining,
    overdue_min: a.json.minutes_overdue,
    escalation: a.json.escalation_level
  }))
};
return [{json: summary}];
